from lxml import etree
import requests
from zeep import Client

client = Client('http://www.dneonline.com/calculator.asmx?WSDL')

def main():
    while True:
        try:
            policyNumber = input("Enter Policy Number: ")
            customerName = input("Enter Customer Name: ")

            # Create SOAP request
            body = etree.Element('GetPolicyQuote', nsmap={'ns': 'http://tempuri.org/'})
            body.append(etree.Element('ns:PolicyNumber', text=policyNumber))
            body.append(etree.Element('ns:CustomerName', text=customerName))

            # Send SOAP request to third party insurance service
            response = client.service.GetPolicyQuote(body)

            # Print response from third party insurance service
            print("Response: {}".format(response))
        except Exception as e:
            print("Error: {}".format(e))

if __name__ == '__main__':
    main()